1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  priorContracts: number;
4	  firstInsurance?: boolean;
5	};
6	
7	export type Item = Record<string, unknown>;
8	
9	export type Policy = {
10	  customer: Customer;
11	  items: Item[];
12	};
