129	export function quote(policy: Policy): QuoteResult {
130	  const componentsTotal = componentsPremium(policy.items);
131	  const nonComponents = nonComponentsTotals(policy.items);
132	  const itemsTotal = nonComponents.withModifiers + componentsTotal;
133	  const policyBase = nonComponents.base + componentsTotal;
134	  return {
135	    premium: Math.ceil(itemsTotal + totalPolicyAdjustment(policy.customer, policyBase) + PROCESSING_FEE),
136	  };
137	}
